<?php require_once '../../../includes/config.php'; require_once '../../../includes/db.php'; require_once '../../../includes/auth.php'; require_once '../../../includes/helpers.php'; require_role(['admin']); $pdo = get_pdo(); $page_title = 'Edit Jadwal Kuliah'; $id = isset($_GET['id']) ? (int)$_GET['id'] : 0; if (!$id) { flash('error', 'Jadwal tidak ditemukan'); redirect(APP_URL . '/admin/jadwal/index.php'); exit; } $stmt = $pdo->prepare("SELECT * FROM jadwal_kuliah WHERE id_jadwal = ?"); $stmt->execute([$id]); $jadwal = $stmt->fetch(); if (!$jadwal) { flash('error', 'Jadwal tidak ditemukan'); redirect(APP_URL . '/admin/jadwal/index.php'); exit; } $errors = []; $form_data = ['id_matkul' => $jadwal['id_matkul'], 'id_dosen' => $jadwal['id_dosen'], 'id_semester' => $jadwal['id_semester'], 'hari' => $jadwal['hari'], 'jam_mulai' => $jadwal['jam_mulai'], 'jam_selesai' => $jadwal['jam_selesai'], 'ruang' => $jadwal['ruang'], 'kuota' => $jadwal['kuota']]; if ($_SERVER['REQUEST_METHOD'] === 'POST') { if (empty($_POST['_csrf']) || !csrf_verify($_POST['_csrf'])) { $errors[] = 'CSRF token tidak valid'; } $form_data['jam_mulai'] = trim($_POST['jam_mulai'] ?? ''); $form_data['jam_selesai'] = trim($_POST['jam_selesai'] ?? ''); $form_data['ruang'] = trim($_POST['ruang'] ?? ''); $form_data['kuota'] = (int)($_POST['kuota'] ?? 40); if (empty($form_data['jam_mulai']) || empty($form_data['jam_selesai'])) { $errors[] = 'Jam mulai dan selesai harus diisi'; } if (empty($form_data['ruang'])) { $errors[] = 'Ruang harus diisi'; } if ($form_data['kuota'] < 1) { $errors[] = 'Kuota minimal 1'; } if (empty($errors)) { try { $stmt = $pdo->prepare("UPDATE jadwal_kuliah SET jam_mulai = ?, jam_selesai = ?, ruang = ?, kuota = ? WHERE id_jadwal = ?"); $stmt->execute([$form_data['jam_mulai'], $form_data['jam_selesai'], $form_data['ruang'], $form_data['kuota'], $id]); flash('success', 'Jadwal berhasil diperbarui'); redirect(APP_URL . '/admin/jadwal/index.php'); exit; } catch (Exception $e) { $errors[] = 'Error: ' . $e->getMessage(); } } } $stmt = $pdo->prepare("SELECT id_matkul, kode_matkul, nama_matkul FROM mata_kuliah ORDER BY nama_matkul"); $stmt->execute(); $matkul_list = $stmt->fetchAll(); $stmt = $pdo->prepare("SELECT nidn, nama FROM dosen ORDER BY nama"); $stmt->execute(); $dosen_list = $stmt->fetchAll(); $stmt = $pdo->prepare("SELECT id_semester, tahun_ajaran, tingkatan_semester FROM semester ORDER BY tahun_ajaran DESC"); $stmt->execute(); $semester_list = $stmt->fetchAll(); ?> <!DOCTYPE html> <html lang="id"> <head> <meta charset="UTF-8"> <meta name="viewport" content="width=device-width, initial-scale=1.0"> <title><?= h($page_title) ?> - SIAKAD Gallery</title> <link rel="stylesheet" href="<?= APP_URL ?>/assets/css/style.css"> <link rel="stylesheet" href="https://cdn.jsdelivr.net/npm/bootstrap-icons@1.10.0/font/bootstrap-icons.css"> <style> .form-container { background: white; border-radius: 16px; padding: 32px; box-shadow: 0 2px 10px rgba(11, 30, 79, 0.06); max-width: 600px; } .form-group { margin-bottom: 20px; } .form-label { display: block; font-weight: 600; color: #0B1E4F; margin-bottom: 8px; font-size: 14px; } .form-control, .form-select { width: 100%; padding: 10px 14px; border: 1px solid #E4E7EE; border-radius: 8px; font-size: 14px; font-family: inherit; } .form-control:disabled { background: #F5F6FA; color: #6B7489; cursor: not-allowed; } .form-row { display: grid; grid-template-columns: 1fr 1fr; gap: 20px; } .form-actions { display: flex; gap: 12px; margin-top: 32px; padding-top: 24px; border-top: 1px solid #E4E7EE; } .btn-secondary { padding: 10px 20px; border-radius: 8px; border: 1px solid #E4E7EE; background: white; color: #2C3A59; text-decoration: none; cursor: pointer; font-weight: 500; } .alert-danger { background: #FFEBEE; border: 1px solid #EF9A9A; color: #C62828; padding: 12px 16px; border-radius: 8px; margin-bottom: 20px; } </style> </head> <body> <div class="app-container"> <?php include '../../../includes/header.php'; ?> <div class="main-content"> <?php include '../../../includes/sidebar.php'; ?> <div class="content-area"> <h1 style="margin-bottom: 24px;"><?= h($page_title) ?></h1> <div class="form-container"> <?php if (!empty($errors)): ?> <div class="alert-danger"> <ul style="margin: 0; padding-left: 20px;"> <?php foreach ($errors as $error): ?> <li><?= h($error) ?></li> <?php endforeach; ?> </ul> </div> <?php endif; ?> <form method="POST"> <input type="hidden" name="_csrf" value="<?= csrf_token() ?>"> <div class="form-row"> <div class="form-group"> <label class="form-label">Mata Kuliah</label> <select class="form-select" disabled> <?php foreach ($matkul_list as $m): ?> <?php if ($m['id_matkul'] == $form_data['id_matkul']): ?> <option selected><?= h($m['kode_matkul'] . ' - ' . $m['nama_matkul']) ?></option> <?php endif; ?> <?php endforeach; ?> </select> </div> <div class="form-group"> <label class="form-label">Dosen</label> <select class="form-select" disabled> <?php foreach ($dosen_list as $d): ?> <?php if ($d['nidn'] == $form_data['id_dosen']): ?> <option selected><?= h($d['nama']) ?></option> <?php endif; ?> <?php endforeach; ?> </select> </div> </div> <div class="form-row"> <div class="form-group"> <label class="form-label">Hari</label> <input type="text" class="form-control" value="<?= h($form_data['hari']) ?>" disabled> </div> <div class="form-group"> <label class="form-label">Semester</label> <select class="form-select" disabled> <?php foreach ($semester_list as $s): ?> <?php if ($s['id_semester'] == $form_data['id_semester']): ?> <option selected><?= h($s['tahun_ajaran'] . ' ' . ucfirst($s['tingkatan_semester'])) ?></option> <?php endif; ?> <?php endforeach; ?> </select> </div> </div> <div class="form-row"> <div class="form-group"> <label class="form-label">Jam Mulai <span style="color: #E04F5F;">*</span></label> <input type="time" name="jam_mulai" class="form-control" value="<?= h($form_data['jam_mulai']) ?>" required> </div> <div class="form-group"> <label class="form-label">Jam Selesai <span style="color: #E04F5F;">*</span></label> <input type="time" name="jam_selesai" class="form-control" value="<?= h($form_data['jam_selesai']) ?>" required> </div> </div> <div class="form-row"> <div class="form-group"> <label class="form-label">Ruang <span style="color: #E04F5F;">*</span></label> <input type="text" name="ruang" class="form-control" value="<?= h($form_data['ruang']) ?>" maxlength="30" required> </div> <div class="form-group"> <label class="form-label">Kuota <span style="color: #E04F5F;">*</span></label> <input type="number" name="kuota" class="form-control" value="<?= $form_data['kuota'] ?>" min="1" required> </div> </div> <div class="form-actions"> <button type="submit" class="btn btn-primary"><i class="bi bi-check-circle"></i> Simpan Perubahan</button> <a href="<?= APP_URL ?>/admin/jadwal/index.php" class="btn-secondary"><i class="bi bi-x-circle"></i> Batal</a> </div> </form> </div> </div> </div> </div> <?php include '../../../includes/footer.php'; ?> </body> </html>
